instruction:
Classic for loop: init, condition, update:

```cpp
for (int i = 0; i < 5; i++) {
    // runs 5 times
}
```

Run this, then try changing the step to `i += 2` for odd numbers.

starter:
#include <iostream>
using namespace std;

int main() {
    for (int i = 1; i <= 5; i++) {
        cout << "Step " << i << endl;
    }
    return 0;
}

instruction:
C++11 range-based for is cleaner when you don't need the index:

```cpp
for (auto& item : container) {
    // item is each element
}
```

Use `auto&` to avoid copying. Use `const auto&` for read-only.

starter:
#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<string> fruits = {"Apple", "Banana", "Cherry", "Date"};

    // Range-based for:
    for (const auto& fruit : fruits) {
        cout << fruit << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n = 1;
    while (n <= 100) {
        if (n * n > 100) {
            cout << "First square > 100: " << n * n << " (n=" << n << ")" << endl;
            break;
        }
        n++;
    }

    // Count down:
    int count = 5;
    while (count > 0) {
        cout << count << " ";
        count--;
    }
    cout << "GO!" << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n = 1;
    do {
        cout << n << " ";
        n *= 2;
    } while (n <= 64);
    cout << endl;

    // Sum using do-while:
    int sum = 0, i = 1;
    do {
        sum += i;
        i++;
    } while (i <= 10);
    cout << "1+2+...+10 = " << sum << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Find first number divisible by 7 AND 11:
    for (int n = 1; n <= 1000; n++) {
        if (n % 7 == 0 && n % 11 == 0) {
            cout << "First: " << n << endl;
            break;
        }
    }

    // Print 1-20, skip multiples of 3:
    for (int i = 1; i <= 20; i++) {
        if (i % 3 == 0) continue;
        cout << i << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    for (int i = 1; i <= 5; i++) {
        for (int j = 1; j <= 5; j++) {
            cout << setw(4) << i * j;
        }
        cout << endl;
    }
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    for (int i = 1; i <= 30; i++) {
        if      (i % 15 == 0) cout << "FizzBuzz" << endl;
        else if (i % 3  == 0) cout << "Fizz"     << endl;
        else if (i % 5  == 0) cout << "Buzz"     << endl;
        else                  cout << i           << endl;
    }
    return 0;
}
